import { DestroyRef, inject, Injectable } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { filter } from 'rxjs';
import {
  AXEventData,
  AXEventService,
  AXSystemEvents,
} from '@acorex/core/events';

@Injectable({ providedIn: 'root' })
export class AppEventsDemo {
  private events = inject(AXEventService);
  private destroyRef = inject(DestroyRef);

  constructor() {
    // Observable API — listen to typed system events via onEvent
    this.events.onEvent
      .pipe(
        filter(
          (event: AXEventData) =>
            event.type === AXSystemEvents.AXLanguageChanged,
        ),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe((event) => {
        console.log('Active language:', event.payload);
      });

    // Callback API — register handlers with on(), trigger with broadcast()
    this.events.on('APP_CART_UPDATED', (payload: { itemCount: number }) => {
      console.log('Cart badge:', payload.itemCount);
    });
  }

  /** Emit into the onEvent Observable stream */
  changeLanguage(lang: string) {
    this.events.emitEvent({
      type: AXSystemEvents.AXLanguageChanged,
      payload: lang,
    });
  }

  /** Notify all callbacks registered for a string key */
  updateCart(itemCount: number) {
    this.events.broadcast('APP_CART_UPDATED', { itemCount });
  }
}

import { Component, DestroyRef, inject, OnInit, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { filter } from 'rxjs/operators';
import {
  AXEventData,
  AXEventService,
  AXSystemEvents,
} from '@acorex/core/events';

@Component({
  selector: 'app-language-watcher',
  template: `<p>Active language: {{ activeLang() }}</p>`,
})
export class LanguageWatcherComponent implements OnInit {
  private eventService = inject(AXEventService);
  private destroyRef = inject(DestroyRef);

  activeLang = signal('en-US');

  ngOnInit() {
    this.eventService.onEvent
      .pipe(
        filter(
          (event: AXEventData) =>
            event.type === AXSystemEvents.AXLanguageChanged,
        ),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe((event) => {
        this.activeLang.set(event.payload as string);
      });
  }

  changeLanguage(lang: string) {
    this.eventService.emitEvent({
      type: AXSystemEvents.AXLanguageChanged,
      payload: lang,
    });
  }
}

import { Component, inject, viewChild } from '@angular/core';
import { AXDrawerComponent } from '@acorex/components/drawer';
import { AXEventService } from '@acorex/core/events';

const OPEN_DRAWER = 'OPEN-DRAWER';

@Component({
  selector: 'app-layout',
  template: `
    <button (click)="openDrawer()">Menu</button>
    <ax-drawer #drawer>Side menu content</ax-drawer>
  `,
})
export class LayoutComponent {
  private eventService = inject(AXEventService);
  drawer = viewChild.required<AXDrawerComponent>('drawer');

  constructor() {
    // Listen from anywhere in the app
    this.eventService.on(OPEN_DRAWER, () => {
      this.drawer().open();
    });
  }

  openDrawer() {
    // Trigger from any component via broadcast
    this.eventService.broadcast(OPEN_DRAWER);
  }
}

import { AXSystemEvents } from '@acorex/core/events';

// Emitted by AXTranslationService.setActiveLang()
AXSystemEvents.AXLanguageChanged; // 'AX_LANGUAGE_CHANGED'

// Emitted by AXTranslationLoaderService after loading translations
AXSystemEvents.AXLanguageLoaded;  // 'AX_LANGUAGE_LOADED'

// Emitted by AXCalendarService.setActiveCalendar()
AXSystemEvents.AXCalendarChanged; // 'AX_CALENDAR_CHANGED'

// Locale events (reserved for locale module)
AXSystemEvents.AXLocaleChanged;   // 'AX_LOCALE_CHANGED'
AXSystemEvents.AXLocaleLoaded;    // 'AX_LOCALE_LOADED'

import { inject } from '@angular/core';
import { filter, map, merge, startWith } from 'rxjs';
import {
  AXEventData,
  AXEventService,
  AXSystemEvents,
} from '@acorex/core/events';

export class RefreshOnSystemChange {
  private eventService = inject(AXEventService);

  private triggers = Object.values(AXSystemEvents) as string[];

  /** Re-runs whenever language, locale, or calendar changes */
  refresh$ = this.eventService.onEvent.pipe(
    filter((event: AXEventData) => this.triggers.includes(event.type)),
    startWith(null),
    map(() => this.loadData()),
  );

  private loadData() {
    return { updatedAt: Date.now() };
  }
}

import { inject, Injectable } from '@angular/core';
import { AXEventService } from '@acorex/core/events';

export const AppEvents = {
  CartUpdated: 'APP_CART_UPDATED',
  UserLoggedIn: 'APP_USER_LOGGED_IN',
} as const;

export interface CartUpdatedPayload {
  itemCount: number;
}

@Injectable({ providedIn: 'root' })
export class CartService {
  private eventService = inject(AXEventService);

  addItem() {
    // Update cart...
    this.eventService.broadcast(AppEvents.CartUpdated, {
      itemCount: 3,
    } satisfies CartUpdatedPayload);
  }
}

@Injectable({ providedIn: 'root' })
export class CartBadgeService {
  private eventService = inject(AXEventService);

  constructor() {
    this.eventService.on(AppEvents.CartUpdated, (payload: CartUpdatedPayload) => {
      console.log('Cart badge:', payload.itemCount);
    });
  }
}

import { Component, DestroyRef, inject, OnDestroy } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXEventService } from '@acorex/core/events';

const MY_EVENT = 'MY-FEATURE-EVENT';

@Component({ selector: 'app-feature', template: '' })
export class FeatureComponent implements OnDestroy {
  private eventService = inject(AXEventService);
  private destroyRef = inject(DestroyRef);

  constructor() {
    // Callback bus
    this.eventService.on(MY_EVENT, this.handleEvent);

    // Observable stream — auto-unsubscribes on destroy
    this.eventService.onEvent
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((event) => console.log(event));
  }

  private handleEvent = () => {
    console.log('Event received');
  };

  ngOnDestroy() {
    // Removes ALL callbacks for this key
    this.eventService.destroy(MY_EVENT, this.handleEvent);
  }
}

import { inject } from '@angular/core';
import { filter } from 'rxjs/operators';
import { AXCalendarService } from '@acorex/core/date-time';
import { AXEventService, AXSystemEvents } from '@acorex/core/events';
import { AXTranslationService } from '@acorex/core/translation';

export class AppBootstrap {
  private translation = inject(AXTranslationService);
  private calendar = inject(AXCalendarService);
  private events = inject(AXEventService);

  init() {
    // Changing language emits AXLanguageChanged automatically
    this.translation.setActiveLang('fa-IR');

    // Changing calendar emits AXCalendarChanged automatically
    this.calendar.setActiveCalendar('solar-hijri');

    // React to those events anywhere in the app
    this.events.onEvent
      .pipe(filter((e) => e.type === AXSystemEvents.AXCalendarChanged))
      .subscribe((e) => {
        console.log('Calendar switched:', e.payload);
      });
  }
}
